import { buildSectionPage } from '../../utils/section-page.utils.js';
import { ProjectsService } from '../../services/projects.service.js';
import { queryRecentClientLogs } from '../../services/debug/client-log-buffer.js';
import { getDeviceId, getDeviceLabel } from '../../services/debug/device-identity.js';
import '../log-viewer/log-viewer.component.js';
import type { LogViewer } from '../log-viewer/log-viewer.component.js';
import type { ScreenComponent } from '../../types/screen-component.js';
import { createComponentLogger } from '../../utils/component-logger.js';

const APP_TIME_ZONE = 'Europe/Amsterdam';

export class ProjectsClientLogsScreen extends HTMLElement implements ScreenComponent {
    private readonly log = createComponentLogger('projects-client-logs-screen');
    private initialized = false;
    private serverViewer: LogViewer | null = null;
    private currentDevice = '';
    private loadingEl: HTMLElement | null = null;
    private errorEl: HTMLElement | null = null;
    private retryBtn: HTMLButtonElement | null = null;
    private deviceSelect: HTMLSelectElement | null = null;

    setLoading(): void {
        if (this.loadingEl) this.loadingEl.hidden = false;
        if (this.errorEl) this.errorEl.hidden = true;
        if (this.retryBtn) this.retryBtn.hidden = true;
    }

    setError(err: unknown): void {
        if (this.loadingEl) this.loadingEl.hidden = true;
        if (this.errorEl) {
            this.errorEl.hidden = false;
            this.errorEl.textContent = err instanceof Error ? (err.stack ?? err.message) : String(err);
        }
        if (this.retryBtn) this.retryBtn.hidden = false;
    }

    clearStatus(): void {
        if (this.loadingEl) this.loadingEl.hidden = true;
        if (this.errorEl) this.errorEl.hidden = true;
        if (this.retryBtn) this.retryBtn.hidden = true;
    }

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        const page = buildSectionPage(this, 'Client Logs', 'projects', '/projects');
        this.loadingEl = document.createElement('p');
        this.loadingEl.className = 'screen-loading';
        this.loadingEl.textContent = 'Loading client-log devices...';
        this.errorEl = document.createElement('pre');
        this.errorEl.className = 'screen-error';
        this.errorEl.hidden = true;
        this.retryBtn = document.createElement('button');
        this.retryBtn.className = 'screen-retry';
        this.retryBtn.type = 'button';
        this.retryBtn.textContent = 'Retry';
        this.retryBtn.hidden = true;
        this.retryBtn.addEventListener('click', () => {
            if (this.deviceSelect) void this.populateDeviceSelect(this.deviceSelect);
        });
        page.content.append(this.loadingEl, this.errorEl, this.retryBtn);

        const serverSection = document.createElement('section');
        serverSection.className = 'client-logs-section';
        const serverHeading = document.createElement('h2');
        serverHeading.textContent = 'Server-aggregated (all devices)';
        serverSection.appendChild(serverHeading);

        const deviceBar = document.createElement('div');
        deviceBar.className = 'client-logs-device-bar';
        const deviceLabel = document.createElement('label');
        deviceLabel.textContent = 'Device:';
        const deviceSelect = document.createElement('select');
        deviceSelect.dataset.testid = 'client-logs-device-select';
        this.deviceSelect = deviceSelect;
        deviceLabel.appendChild(deviceSelect);
        deviceBar.appendChild(deviceLabel);
        serverSection.appendChild(deviceBar);

        const serverViewer = document.createElement('log-viewer') as LogViewer;
        serverViewer.availableLevels = ['debug', 'info', 'warn', 'error'];
        serverViewer.dataset.testid = 'client-logs-server-viewer';
        serverViewer.source = (filters) => {
            if (!this.currentDevice) {
                return Promise.resolve({
                    date: Temporal.Now.zonedDateTimeISO(APP_TIME_ZONE).toPlainDate().toString(),
                    entries: [],
                    total: 0,
                });
            }
            return ProjectsService.fetchClientLogs({
                device: this.currentDevice,
                level: filters.level,
                search: filters.search,
            });
        };
        serverSection.appendChild(serverViewer);
        this.serverViewer = serverViewer;

        deviceSelect.addEventListener('change', () => {
            this.currentDevice = deviceSelect.value;
            serverViewer.refresh();
        });

        const localSection = document.createElement('section');
        localSection.className = 'client-logs-section';
        const localHeading = document.createElement('h2');
        localHeading.textContent = `Local (${getDeviceLabel()} — ${getDeviceId().slice(0, 8)})`;
        localSection.appendChild(localHeading);

        const localViewer = document.createElement('log-viewer') as LogViewer;
        localViewer.availableLevels = ['debug', 'info', 'warn', 'error'];
        localViewer.dataset.testid = 'client-logs-local-viewer';
        localViewer.source = (filters) => queryRecentClientLogs(filters);
        localSection.appendChild(localViewer);

        page.content.append(serverSection, localSection);

        void this.populateDeviceSelect(deviceSelect);
    }

    private async populateDeviceSelect(select: HTMLSelectElement): Promise<void> {
        this.setLoading();
        try {
            const { devices } = await ProjectsService.fetchClientLogDevices();
            select.replaceChildren();
            if (devices.length === 0) {
                const option = document.createElement('option');
                option.value = '';
                option.textContent = '(no devices)';
                select.appendChild(option);
                this.clearStatus();
                return;
            }
            for (const device of devices) {
                const option = document.createElement('option');
                option.value = device.device_id;
                option.textContent = `${device.device_label} (${device.device_id.slice(0, 8)})`;
                select.appendChild(option);
            }
            this.currentDevice = devices[0].device_id;
            select.value = this.currentDevice;
            this.clearStatus();
            this.serverViewer?.refresh();
        } catch (error) {
            this.log.error('fetchClientLogDevices failed:', error);
            const option = document.createElement('option');
            option.value = '';
            option.textContent = '(failed to load devices)';
            select.replaceChildren(option);
            this.setError(error);
        }
    }
}

if (!customElements.get('projects-client-logs-screen')) {
    customElements.define('projects-client-logs-screen', ProjectsClientLogsScreen);
}
